INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (125801, "リリ", 40011, 1, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 0, 2, 1, 24001, 1, 321);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (126001, "クリア", 40011, 1, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 0, 2, 1, 24001, 2, 322);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (126101, "プレシア", 40011, 1, "んーと。\nこれ、あげる。\nはい", 0, 2, 1, 24001, 3, 323);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (125801, "リリ", 40011, 2, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 0, 2, 1, 24001, 4, 324);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (126001, "クリア", 40011, 2, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 0, 2, 1, 24001, 5, 325);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (126101, "プレシア", 40011, 2, "お兄。\nきてくれて、うれしい", 0, 2, 1, 24001, 6, 326);
